SELECT

FROM user_point_journal
WHERE user_id   = #{userId}
  AND deleted_at IS NULL
ORDER BY created_at DESC
LIMIT #{limit}

SELECT

FROM user_point_journal
WHERE user_id    = #{userId}
  AND deleted_at IS NULL

      AND source_type = #{sourceType}

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM user_point_journal
WHERE user_id    = #{userId}
  AND deleted_at IS NULL

      AND source_type = #{sourceType}
